/**
 * Normalizes Malaysian phone numbers to +601XXXXX format.
 * E.g. "012-345 6789" -> "+60123456789"
 *      "6012.3456789" -> "+60123456789"
 *      "+60 12-345 6789" -> "+60123456789"
 */
function format_malaysian_phone($phone) {
    if (empty($phone)) return '';
    
    // Strip all non-digit characters
    $digits = preg_replace('/\D/', '', $phone);
    
    if (empty($digits)) return $phone; // Return as-is if no digits
    
    // If it starts with 601, prepends '+'
    if (substr($digits, 0, 3) === '601') {
        return '+' . $digits;
    }
    
    // If it starts with 01, replace '01' with '+601'
    if (substr($digits, 0, 2) === '01') {
        return '+6' . $digits;
    }
    
    // If it starts with 1 (e.g. 123456789), prepend '+60'
    if (substr($digits, 0, 1) === '1') {
        return '+60' . $digits;
    }
    
    // If it already starts with 60 (but not 601, e.g. international or older formatting), prepend '+'
    if (substr($digits, 0, 2) === '60') {
        return '+' . $digits;
    }
    
    // Default fallback: if it is already formatted or other international number, return with '+' if not present
    if (substr($phone, 0, 1) === '+') {
        return '+' . $digits;
    }
    
    return '+60' . ltrim($digits, '0');
}

/**
 * Normalizes Malaysian NRIC to XXXXXX-XX-XXXX format.
 * E.g. "950101-14-5555" -> "950101-14-5555"
 *      "950101145555" -> "950101-14-5555"
 */
function format_malaysian_nric($nric) {
    if (empty($nric)) return '';
    
    // Strip all non-alphanumeric/non-digits characters
    $digits = preg_replace('/\D/', '', $nric);
    
    // Malaysian NRIC is exactly 12 digits
    if (strlen($digits) === 12) {
        return substr($digits, 0, 6) . '-' . substr($digits, 6, 2) . '-' . substr($digits, 8, 4);
    }
    
    // If it's a foreign passport or other formats, keep original or trimmed
    return strtoupper(trim($nric));
}

